// UNPATCHED FileStandardInformation branch (rsi = FCB, rdi = output buffer, bl = 0):
if (ebp >= 0x18) {
    *(DWORD*)(rdi+0x00) = *(DWORD*)(rsi+0x18);   // AllocationSize.LowPart
    *(DWORD*)(rdi+0x04) = *(DWORD*)(rsi+0x1c);   // AllocationSize.HighPart
    *(DWORD*)(rdi+0x08) = *(DWORD*)(rsi+0x20);   // EndOfFile.LowPart
    *(DWORD*)(rdi+0x0c) = *(DWORD*)(rsi+0x24);   // EndOfFile.HighPart
    *(BYTE*)(rdi+0x14)  = 0;                      // DeletePending hardcoded 0
    *(BYTE*)(rdi+0x15)  = r15b & 0x10;            // Directory/reparse
    *(DWORD*)(rdi+0x10) = *(DWORD*)(rsi+0xe8);    // NumberOfLinks = FCB+0xE8 (disclosure)
}

// PATCHED:
    *(DWORD*)(rdi+0x10) = 1;                       // NumberOfLinks = 1
    *(BYTE*)(rdi+0x14)  = *(BYTE*)(rsi+0x8c) & 1;  // DeletePending = real FCB state

